args.sparql:
SELECT ?college ?collegeLabel ?inception WHERE { 
  ?college rdfs:label ?collegeLabel .
  FILTER(LANG(?collegeLabel) = "en") .
  ?college wdt:P31/wdt:P279* wd:Q494230 .
  { ?college wdt:P131 wd:Q1186 }
  UNION
  { ?college wdt:P131 ?district . ?district wdt:P131 wd:Q1186 } .
  FILTER(!STRCONTAINS(LCASE(?collegeLabel), "government")) .
  OPTIONAL { ?college wdt:P571 ?inception }
}
ORDER BY ?inception
LIMIT 1
